// ── Code - Fetch Board Config ────────────────────────────────────────────
// Recebe conversation_id + company_id, percorre:
//   conversations → leads → board_stages → boards
// Retorna ai_enabled, ai_prompt, instance_name, phone para o agente.

const body   = $input.first().json.body ?? $input.first().json;
const { conversation_id, company_id, content_text, content_type } = body;

const SUPA_URL = 'https://fhkhamwrfwtacwydukvb.supabase.co';
const SUPA_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZoa2hhbXdyZnd0YWN3eWR1a3ZiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTMyNjcxMywiZXhwIjoyMDgwOTAyNzEzfQ.slNbow0lzBpryTaPPNNPDOV5x_uBqRHQZR38RRk92sY';
const headers = { 'apikey': SUPA_KEY, 'Authorization': `Bearer ${SUPA_KEY}` };

// 1. Conversa → lead_id + channel_connection_id
const convRes  = await fetch(`${SUPA_URL}/rest/v1/conversations?id=eq.${conversation_id}&company_id=eq.${company_id}&select=lead_id,channel_connection_id`, { headers });
const convData = await convRes.json();
if (!convData.length) return [{ json: { ai_enabled: false, error: 'conversation_not_found' } }];
const { lead_id, channel_connection_id } = convData[0];

// 2. Lead → column_id + phone
const leadRes  = await fetch(`${SUPA_URL}/rest/v1/leads?id=eq.${lead_id}&company_id=eq.${company_id}&select=column_id,phone,name`, { headers });
const leadData = await leadRes.json();
if (!leadData.length) return [{ json: { ai_enabled: false, error: 'lead_not_found' } }];
const { column_id, phone, name: lead_name } = leadData[0];

// 3. Stage → board_id
const stageRes  = await fetch(`${SUPA_URL}/rest/v1/board_stages?id=eq.${column_id}&select=board_id`, { headers });
const stageData = await stageRes.json();
if (!stageData.length) return [{ json: { ai_enabled: false, error: 'stage_not_found' } }];
const { board_id } = stageData[0];

// 4. Board → ai_enabled + ai_prompt
const boardRes  = await fetch(`${SUPA_URL}/rest/v1/boards?id=eq.${board_id}&company_id=eq.${company_id}&select=ai_enabled,ai_prompt`, { headers });
const boardData = await boardRes.json();
if (!boardData.length) return [{ json: { ai_enabled: false, error: 'board_not_found' } }];
const { ai_enabled, ai_prompt } = boardData[0];

// 5. Channel connection → instance_name
const connRes  = await fetch(`${SUPA_URL}/rest/v1/channel_connections?id=eq.${channel_connection_id}&select=instance`, { headers });
const connData = await connRes.json();
const instance_name = connData[0]?.instance || '';

return [{
  json: {
    conversation_id,
    company_id,
    content_text,
    content_type,
    lead_id,
    phone,
    lead_name,
    ai_enabled,
    ai_prompt,
    instance_name
  }
}];

// ── Code - Run Agent ─────────────────────────────────────────────────────
// 1. Busca histórico de mensagens
// 2. Chama OpenAI
// 3. Envia resposta via Evolution API
// 4. Insere mensagem no Supabase (sender_type = 'agent')

const config = $('Code - Fetch Board Config').first().json;
const { conversation_id, company_id, ai_prompt, instance_name, phone, content_text } = config;

const SUPA_URL  = 'https://fhkhamwrfwtacwydukvb.supabase.co';
const SUPA_KEY  = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZoa2hhbXdyZnd0YWN3eWR1a3ZiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTMyNjcxMywiZXhwIjoyMDgwOTAyNzEzfQ.slNbow0lzBpryTaPPNNPDOV5x_uBqRHQZR38RRk92sY';
const EVO_URL   = 'https://easypanel.julianosalles.com.br';
const EVO_KEY   = '4DD73F0CC46E-407C-B70D-48C9175EC89B';
const OPENAI_KEY = 'sk-CONFIGURE_SUA_CHAVE_OPENAI_AQUI'; // ← substitua pela sua chave OpenAI

const supaHeaders = {
  'apikey': SUPA_KEY,
  'Authorization': `Bearer ${SUPA_KEY}`,
  'Content-Type': 'application/json'
};

// 1. Buscar histórico (últimas 8 mensagens, mais recentes primeiro)
const histRes  = await fetch(`${SUPA_URL}/rest/v1/messages?conversation_id=eq.${conversation_id}&company_id=eq.${company_id}&order=sent_at.desc&limit=8`, { headers: supaHeaders });
const histData = await histRes.json();

// Montar histórico (sem a última msg, que é a atual — já está em content_text)
const chatHistory = (Array.isArray(histData) ? histData : [])
  .slice(1)          // pula a mensagem mais recente (já está em content_text)
  .reverse()         // ordem cronológica
  .map(m => ({
    role: m.sender_type === 'lead' ? 'user' : 'assistant',
    content: (m.content || '').trim()
  }))
  .filter(m => m.content);

const systemPrompt = (ai_prompt || '').trim() ||
  'Você é um assistente de vendas profissional e cordial. Responda sempre em português brasileiro de forma clara e objetiva.';

// 2. Chamar OpenAI
const aiRes = await fetch('https://api.openai.com/v1/chat/completions', {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${OPENAI_KEY}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'gpt-4o-mini',
    messages: [
      { role: 'system', content: systemPrompt },
      ...chatHistory,
      { role: 'user', content: content_text }
    ],
    max_tokens: 500,
    temperature: 0.7
  })
});
const aiData = await aiRes.json();
const aiText = aiData.choices?.[0]?.message?.content?.trim();

if (!aiText) {
  return [{ json: { ok: false, error: 'openai_no_response', detail: aiData } }];
}

// 3. Enviar via Evolution API
const instanceEncoded = encodeURIComponent(instance_name);
await fetch(`${EVO_URL}/message/sendText/${instanceEncoded}`, {
  method: 'POST',
  headers: { 'apikey': EVO_KEY, 'Content-Type': 'application/json' },
  body: JSON.stringify({
    number: `${phone}@s.whatsapp.net`,
    text: aiText
  })
});

// 4. Inserir mensagem do agente no Supabase
await fetch(`${SUPA_URL}/rest/v1/rpc/insert_message`, {
  method: 'POST',
  headers: supaHeaders,
  body: JSON.stringify({
    p_company_id:          company_id,
    p_conversation_id:     conversation_id,
    p_external_message_id: `agent-${Date.now()}`,
    p_direction:           'outbound',
    p_sender_type:         'agent',
    p_content:             aiText,
    p_content_type:        'text',
    p_sent_at:             new Date().toISOString(),
    p_media_url:           null,
    p_metadata:            {}
  })
});

return [{ json: { ok: true, ai_response: aiText } }];
